import{_ as r,I as n,o as e,c as d,a7 as o,b as i,w as s,a as l,J as c,a8 as g,an as h}from"./chunks/framework.D8GRgv03.js";const A=JSON.parse('{"title":"许愿","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"wish.md","filePath":"wish.md"}'),p={name:"wish.md"};function b(m,t,_,f,u,E){const a=n("Mermaid");return e(),d("div",null,[t[1]||(t[1]=o('<h1 id="许愿" tabindex="-1">许愿 <a class="header-anchor" href="#许愿" aria-label="Permalink to “许愿”">​</a></h1><p>相关文档：<a href="/music-free-site/playlist.html">歌单</a> · <a href="/music-free-site/music.html">音乐管理</a> · <a href="/music-free-site/plugin-collection.html">插件合集</a> · <a href="/music-free-site/user.html">用户</a></p><p><img src="'+h+'" alt=""></p><h2 id="_1-模块概述" tabindex="-1">1. 模块概述 <a class="header-anchor" href="#_1-模块概述" aria-label="Permalink to “1. 模块概述”">​</a></h2><p><strong>歌曲许愿</strong>连接「用户缺歌需求」与「管理员入库运维」：用户为<strong>尚未入库</strong>的曲目提交元数据（作品名、艺术家、专辑），管理员在后台检索、下载或标记实现后，愿望状态闭环。</p><p>典型场景：从网易云等平台 <strong><a href="/music-free-site/playlist.html">导入歌单</a></strong> 后，部分曲目在本地曲库<strong>未匹配</strong>（<code>playable: false</code>）。用户可在歌单详情 <strong>逐首许愿</strong> 或 <strong>许愿全部未匹配</strong>，管理员在 <strong>愿望管理</strong> 页统一处理。</p>',6)),(e(),i(g,null,{default:s(()=>[c(a,{id:"mermaid-18",class:"mermaid",graph:"flowchart%20LR%0A%20%20subgraph%20user%20%5B%E7%94%A8%E6%88%B7%5D%0A%20%20%20%20M%5B%E6%89%8B%E5%8A%A8%E6%96%B0%E5%BB%BA%E6%84%BF%E6%9C%9B%5D%0A%20%20%20%20P%5B%E6%AD%8C%E5%8D%95%E6%9C%AA%E5%8C%B9%E9%85%8D%E6%9B%B2%E7%9B%AE%E8%AE%B8%E6%84%BF%5D%0A%20%20%20%20L%5B%E6%88%91%E7%9A%84%E6%84%BF%E6%9C%9B%E6%B8%85%E5%8D%95%5D%0A%20%20end%0A%20%20subgraph%20admin%20%5B%E7%AE%A1%E7%90%86%E5%91%98%5D%0A%20%20%20%20W%5B%E6%84%BF%E6%9C%9B%E7%AE%A1%E7%90%86%20%2Fadmin%2Fwish%5D%0A%20%20%20%20RS%5B%E8%BF%9C%E7%A8%8B%E6%90%9C%E7%B4%A2%5D%0A%20%20%20%20RD%5B%E8%BF%9C%E7%A8%8B%E4%B8%8B%E8%BD%BD%E5%85%A5%E5%BA%93%5D%0A%20%20end%0A%20%20subgraph%20db%20%5B%E6%95%B0%E6%8D%AE%E5%BA%93%5D%0A%20%20%20%20SW%5B(song_wishes)%5D%0A%20%20%20%20Songs%5B(songs)%5D%0A%20%20end%0A%20%20M%20--%3E%20SW%0A%20%20P%20--%3E%20SW%0A%20%20L%20--%3E%20SW%0A%20%20W%20--%3E%20RS%0A%20%20RS%20--%3E%20RD%0A%20%20RD%20--%3E%20Songs%0A%20%20RD%20--%3E%7C%E6%8C%89%20norm_key%20%E6%89%B9%E9%87%8F%20fulfill%7C%20SW%0A"})]),fallback:s(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=o(`<p><strong>能力边界</strong>：</p><ul><li>愿望仅通过 <strong>内部 REST + Web UI</strong> 暴露，<strong>不在 OpenSubsonic</strong> 协议中提供。</li><li>系统<strong>不会</strong>根据愿望自动后台下载；须管理员手动选源下载，或曲目已由其他途径入库时使用 <strong>标记已实现</strong>。</li></ul><h2 id="_2-访问与权限" tabindex="-1">2. 访问与权限 <a class="header-anchor" href="#_2-访问与权限" aria-label="Permalink to “2. 访问与权限”">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>入口</th><th>路径</th></tr></thead><tbody><tr><td>普通用户</td><td>头像菜单 → <strong>我的愿望</strong></td><td><code>/wishes</code></td></tr><tr><td>普通用户</td><td>外部歌单详情 → <strong>许愿</strong> / <strong>许愿全部未匹配</strong></td><td><code>/playlists/:id</code></td></tr><tr><td>管理员</td><td>管理后台侧栏 → <strong>愿望管理</strong></td><td><code>/admin/wish</code></td></tr></tbody></table><ul><li><strong>用户端</strong>：须登录；只能查看与管理<strong>本人</strong>愿望。</li><li><strong>管理端</strong>：须管理员权限（<code>requiresAdmin</code>）；非管理员访问页面或 API 会被拒绝。</li></ul><h2 id="_3-愿望状态与去重" tabindex="-1">3. 愿望状态与去重 <a class="header-anchor" href="#_3-愿望状态与去重" aria-label="Permalink to “3. 愿望状态与去重”">​</a></h2><h3 id="_3-1-状态机" tabindex="-1">3.1 状态机 <a class="header-anchor" href="#_3-1-状态机" aria-label="Permalink to “3.1 状态机”">​</a></h3><table tabindex="0"><thead><tr><th>状态</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>待处理</td><td><code>pending</code></td><td>等待管理员处理</td></tr><tr><td>已实现</td><td><code>fulfilled</code></td><td>管理员标记实现，或下载成功后批量更新</td></tr><tr><td>已拒绝</td><td><code>rejected</code></td><td>管理员填写拒绝原因；用户可 <strong>重新许愿</strong></td></tr></tbody></table><h3 id="_3-2-归一化键-norm-key" tabindex="-1">3.2 归一化键（<code>norm_key</code>） <a class="header-anchor" href="#_3-2-归一化键-norm-key" aria-label="Permalink to “3.2 归一化键（norm_key）”">​</a></h3><p>系统对 <strong>作品名 + 艺术家 + 专辑</strong> 做归一化（去首尾空白、合并连续空白、统一全角空格等），拼接为 <code>title|artist|album</code> 作为 <code>norm_key</code>：</p><ul><li><strong>去重</strong>：同一用户对相同 <code>norm_key</code> 在存在 <strong><code>pending</code></strong> 愿望时，不能再次创建。</li><li><strong>批量实现</strong>：管理员将某条愿望实现时，所有用户、所有 <strong><code>pending</code></strong> 且 <strong>相同 <code>norm_key</code></strong> 的记录一并变为 <code>fulfilled</code>。</li><li><strong>已实现后可再许愿</strong>：某用户该键上一条为 <code>fulfilled</code> 时，允许再次创建新的 <code>pending</code>（例如补录不同版本）。</li></ul><p>来自歌单的许愿还会按 <strong><code>playlist_song_id</code></strong> 检查：若该条目已有 <code>pending</code> 愿望，视为重复。</p><h3 id="_3-3-歌单详情上的-wishstatus" tabindex="-1">3.3 歌单详情上的 <code>wishStatus</code> <a class="header-anchor" href="#_3-3-歌单详情上的-wishstatus" aria-label="Permalink to “3.3 歌单详情上的 wishStatus”">​</a></h3><p><code>GET /rest/api/v1/playlists/:id</code> 每条曲目对<strong>当前登录用户</strong>附带 <code>wishStatus</code>：</p><table tabindex="0"><thead><tr><th>值</th><th>含义</th></tr></thead><tbody><tr><td><code>none</code></td><td>未许愿，或愿望已实现但条目<strong>仍不可播</strong>（本地仍未匹配，可继续许愿）</td></tr><tr><td><code>wished</code></td><td>存在 <code>pending</code> 愿望</td></tr><tr><td><code>fulfilled</code></td><td>存在 <code>fulfilled</code> 愿望且条目<strong>已可播</strong></td></tr></tbody></table><h2 id="_4-用户端操作" tabindex="-1">4. 用户端操作 <a class="header-anchor" href="#_4-用户端操作" aria-label="Permalink to “4. 用户端操作”">​</a></h2><h3 id="_4-1-我的愿望-wishes" tabindex="-1">4.1 我的愿望（<code>/wishes</code>） <a class="header-anchor" href="#_4-1-我的愿望-wishes" aria-label="Permalink to “4.1 我的愿望（/wishes）”">​</a></h3><ul><li><strong>入口</strong>：登录后点击右上角头像 → <strong>我的愿望</strong>。</li><li><strong>筛选</strong>：待处理（<code>pending</code>）、已实现（<code>fulfilled</code>）、已拒绝（<code>rejected</code>）。</li><li><strong>新建愿望</strong>：填写作品名、艺术家（必填）、专辑（可选）；提交后进入待处理列表。</li><li><strong>已拒绝</strong>：展示 <code>rejectReason</code>；点击 <strong>重新许愿</strong> 基于原信息创建新的 <code>pending</code> 记录。</li></ul><h3 id="_4-2-外部歌单详情" tabindex="-1">4.2 外部歌单详情 <a class="header-anchor" href="#_4-2-外部歌单详情" aria-label="Permalink to “4.2 外部歌单详情”">​</a></h3><p>仅当歌单存在 <strong><code>externalSource</code></strong>（平台导入歌单）且曲目 <strong><code>playable: false</code></strong> 时显示许愿相关 UI：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td>行内 <strong>许愿</strong></td><td>为单首未匹配曲目创建愿望；成功后显示 <strong>已许愿</strong>，不可重复点击</td></tr><tr><td><strong>许愿全部未匹配</strong></td><td>对该歌单所有未匹配且当前用户尚未 <code>pending</code> 的条目批量创建；提示 <code>created</code> / <code>skipped</code> 数量</td></tr><tr><td>点击许愿</td><td><strong>不会</strong>触发播放（与不可播条目行为一致）</td></tr></tbody></table><p>许愿成功后前端会<strong>刷新歌单详情</strong>以更新 <code>wishStatus</code>。</p><blockquote><p><strong>自建歌单</strong>不支持行内许愿；若曲库缺少该曲，请在 <strong>我的愿望</strong> 手动填写元数据，或从曲库 <strong>添加歌曲</strong>。</p></blockquote><h2 id="_5-管理员操作-admin-wish" tabindex="-1">5. 管理员操作（<code>/admin/wish</code>） <a class="header-anchor" href="#_5-管理员操作-admin-wish" aria-label="Permalink to “5. 管理员操作（/admin/wish）”">​</a></h2><h3 id="_5-1-愿望列表" tabindex="-1">5.1 愿望列表 <a class="header-anchor" href="#_5-1-愿望列表" aria-label="Permalink to “5.1 愿望列表”">​</a></h3><ul><li><strong>默认</strong>：仅展示 <strong><code>pending</code></strong>；可切换已实现、已拒绝或全部。</li><li><strong>列信息</strong>：作品名、艺术家、专辑、提交用户、状态、来源等。</li></ul><h3 id="_5-2-实现愿望-推荐-搜索-下载" tabindex="-1">5.2 实现愿望（推荐：搜索 + 下载） <a class="header-anchor" href="#_5-2-实现愿望-推荐-搜索-下载" aria-label="Permalink to “5.2 实现愿望（推荐：搜索 + 下载）”">​</a></h3><p>对待处理愿望：</p><ol><li>点击 <strong>搜索</strong>：侧栏以「作品名 + 艺术家 + 专辑」为关键词，流式调用 <strong><code>POST /rest/api/v1/remote-search</code></strong>（NDJSON），展示各插件候选（与 <a href="/music-free-site/music.html">音乐管理 · 音乐搜索</a> 相同）。</li><li>在结果中选择条目，<strong>下载并实现</strong>：调用 <strong><code>POST /rest/api/v1/admin/wishes/:id/fulfill-download</code></strong>，内部先执行 <code>remoteDownload</code> 入库，再按该愿望的 <code>norm_key</code> <strong>批量</strong> <code>fulfill</code>。</li><li>成功提示 <strong>愿望已实现</strong>，并显示 <code>fulfilledCount</code>（同键待处理条数）。</li></ol><p>下载失败时愿望保持 <code>pending</code>，可换源重试。</p><h3 id="_5-3-其他管理操作" tabindex="-1">5.3 其他管理操作 <a class="header-anchor" href="#_5-3-其他管理操作" aria-label="Permalink to “5.3 其他管理操作”">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>拒绝</strong></td><td>必填拒绝原因；状态变为 <code>rejected</code></td></tr><tr><td><strong>标记已实现</strong></td><td>不经过下载，直接将同 <code>norm_key</code> 下所有 <code>pending</code> 标为 <code>fulfilled</code>（适用于曲目已由其他途径入库）</td></tr></tbody></table><h3 id="_5-4-实现后的歌单关联" tabindex="-1">5.4 实现后的歌单关联 <a class="header-anchor" href="#_5-4-实现后的歌单关联" aria-label="Permalink to “5.4 实现后的歌单关联”">​</a></h3><p>下载或标记实现成功后，服务端会尝试将<strong>相同 <code>norm_key</code></strong> 且仍 <strong>未匹配</strong> 的歌单占位条目，按标题 + 艺术家（或外部元数据）<strong>关联</strong>到新入库的 <code>song_id</code>。</p><p>若本地仍无法匹配，用户侧 <code>wishStatus</code> 可能仍为 <code>none</code>，可引导用户再次 <strong><a href="/music-free-site/playlist.html">同步歌单</a></strong>。</p><h2 id="_6-典型工作流" tabindex="-1">6. 典型工作流 <a class="header-anchor" href="#_6-典型工作流" aria-label="Permalink to “6. 典型工作流”">​</a></h2><h3 id="_6-1-用户侧" tabindex="-1">6.1 用户侧 <a class="header-anchor" href="#_6-1-用户侧" aria-label="Permalink to “6.1 用户侧”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>导入网易云歌单 → 打开详情看到未匹配曲目</span></span>
<span class="line"><span>    → 单首「许愿」或「许愿全部未匹配」</span></span>
<span class="line"><span>    → 「我的愿望」查看待处理</span></span>
<span class="line"><span>    → 管理员入库后状态变为已实现</span></span>
<span class="line"><span>    → 同步歌单 → 条目可播放</span></span></code></pre></div><p>若被拒绝：查看原因 → <strong>重新许愿</strong>。</p><h3 id="_6-2-管理员侧" tabindex="-1">6.2 管理员侧 <a class="header-anchor" href="#_6-2-管理员侧" aria-label="Permalink to “6.2 管理员侧”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/admin/wish 查看待处理愿望</span></span>
<span class="line"><span>    → 搜索 → 选择候选 → 下载并实现</span></span>
<span class="line"><span>    → 同 norm_key 的多用户愿望一并 fulfilled</span></span>
<span class="line"><span>    → 通知用户同步歌单（若仍不可播）</span></span></code></pre></div><p>无远程插件时：先将曲目以其他方式入库（如 <a href="/music-free-site/music.html">音乐管理 · 音乐搜索</a>），再对愿望使用 <strong>标记已实现</strong>。</p><h2 id="_7-常见问题" tabindex="-1">7. 常见问题 <a class="header-anchor" href="#_7-常见问题" aria-label="Permalink to “7. 常见问题”">​</a></h2><p><strong>Q：为什么已实现的愿望在歌单里仍显示「许愿」？</strong><br> A：实现只表示管理员已处理；若下载后歌单条目仍 <code>playable: false</code>（未匹配到本地文件），界面将 <code>wishStatus</code> 置为 <code>none</code>，允许再次许愿。请 <strong>同步歌单</strong> 或检查标签是否与本地一致。</p><p><strong>Q：两名用户许愿同一首歌，管理员只下载一次够吗？</strong><br> A：够。实现时按 <strong><code>norm_key</code></strong> 批量将所有用户的 <code>pending</code> 标为 <code>fulfilled</code>。</p><p><strong>Q：管理员没有远程插件怎么办？</strong><br> A：在 <code>/admin/plugin</code> 安装并启用带 <code>remoteSearch</code> / <code>remoteDownload</code> 的插件；或先将曲目以其他方式入库，再对愿望使用 <strong>标记已实现</strong>。</p><p><strong>Q：拒绝后还能再提交吗？</strong><br> A：可以。在 <strong>我的愿望</strong> 中对已拒绝记录点击 <strong>重新许愿</strong>，或手动新建（若无同键 <code>pending</code>）。</p><p><strong>Q：自建歌单里的歌能许愿吗？</strong><br> A：许愿 UI 仅针对 <strong>平台导入</strong> 且 <strong>未匹配</strong> 的条目。自建歌单请用 <strong>添加歌曲</strong> 从已有曲库选取；若曲库没有该曲，可在 <strong>我的愿望</strong> 手动填写元数据。</p>`,48))])}const B=r(p,[["render",b]]);export{A as __pageData,B as default};
